evaluators.evaluation_logic:
const checkpoints = [];

// Load instrumentation variables
let filterParams = null;
try {
  const raw = localStorage.getItem('task1_hostingFilterParams');
  filterParams = raw ? JSON.parse(raw) : null;
} catch (e) {
  filterParams = null;
}

let checkout = null;
try {
  const raw = localStorage.getItem('task1_checkoutCheapestPlan');
  checkout = raw ? JSON.parse(raw) : null;
} catch (e) {
  checkout = null;
}

// Load data
const hostingPlans = JSON.parse(localStorage.getItem('hosting_plans') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// Determine qualifying hosting plans based on task criteria
const allowedStorageTypes = ['ssd', 'nvme'];
const qualifyingPlans = hostingPlans.filter(p =>
  p &&
  p.status === 'active' &&
  typeof p.storage_gb === 'number' && p.storage_gb >= 50 &&
  allowedStorageTypes.includes(p.storage_type) &&
  typeof p.monthly_price === 'number' && p.monthly_price <= 40 &&
  p.billing_cycle_default === 'monthly'
);

let cheapestPlan = null;
if (qualifyingPlans.length > 0) {
  cheapestPlan = qualifyingPlans.reduce((min, p) => {
    if (!min) return p;
    const mp = typeof p.monthly_price === 'number' ? p.monthly_price : Infinity;
    const mm = typeof min.monthly_price === 'number' ? min.monthly_price : Infinity;
    return mp < mm ? p : min;
  }, null);
}

// CP1 (0.30): User used correct hosting filters (min storage >=50GB, monthly billing, max price <=$40, sorted by price low to high)
const usedCorrectFilter = !!filterParams &&
  typeof filterParams.min_storage_gb === 'number' && filterParams.min_storage_gb >= 50 &&
  filterParams.billing_cycle === 'monthly' &&
  typeof filterParams.max_monthly_price === 'number' && filterParams.max_monthly_price <= 40 &&
  filterParams.sort_by === 'price_low_to_high';

checkpoints.push({ passed: usedCorrectFilter, weight: 0.30 });

// CP2 (0.30): Checkout contains exactly one qualifying hosting plan on a monthly cycle, and recurring total matches that item
let selectedPlanIsQualifying = false;
if (checkout && checkout.hosting_plan_id && checkout.cart_id && checkout.cart_item_id) {
  const plan = hostingPlans.find(p => p.id === checkout.hosting_plan_id);
  if (plan) {
    const meetsCriteria =
      plan.status === 'active' &&
      typeof plan.storage_gb === 'number' && plan.storage_gb >= 50 &&
      allowedStorageTypes.includes(plan.storage_type) &&
      typeof plan.monthly_price === 'number' && plan.monthly_price <= 40 &&
      plan.billing_cycle_default === 'monthly' &&
      checkout.billing_cycle === 'monthly' &&
      typeof checkout.monthly_price === 'number' && checkout.monthly_price === plan.monthly_price &&
      checkout.storage_gb === plan.storage_gb;

    const thisCartItems = cartItems.filter(ci => ci.cart_id === checkout.cart_id);
    const singleItem =
      thisCartItems.length === 1 &&
      thisCartItems[0].id === checkout.cart_item_id &&
      thisCartItems[0].product_type === 'hosting_plan' &&
      thisCartItems[0].product_id === checkout.hosting_plan_id &&
      thisCartItems[0].billing_cycle === 'monthly' &&
      typeof thisCartItems[0].quantity === 'number' && thisCartItems[0].quantity >= 1;

    const recurringMatches =
      typeof checkout.recurring_total === 'number' &&
      typeof thisCartItems[0]?.unit_price === 'number' &&
      checkout.recurring_total === thisCartItems[0].unit_price * thisCartItems[0].quantity;

    selectedPlanIsQualifying = meetsCriteria && singleItem && recurringMatches;
  }
}

checkpoints.push({ passed: selectedPlanIsQualifying, weight: 0.30 });

// CP3 (0.40): The plan selected at checkout is the cheapest qualifying plan
const selectedCheapest = !!checkout && !!cheapestPlan && checkout.hosting_plan_id === cheapestPlan.id;
checkpoints.push({ passed: selectedCheapest, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const requests = JSON.parse(localStorage.getItem('video_production_quote_requests') || '[]');

// Find requests that match the core task criteria
const qualifying = requests.filter(r => {
  if (!r) return false;
  const location = (r.location || '').toLowerCase();
  const duration = typeof r.estimated_duration_seconds === 'number' ? r.estimated_duration_seconds : null;
  const budgetOk = typeof r.max_budget === 'number' && r.max_budget <= 8000;
  const durationOk = duration !== null && duration >= 60 && duration <= 120; // approx 90 seconds
  const locationOk = location.includes('new york');
  const onsiteOk = r.onsite_filming === true;
  const serviceOk = r.service_key === 'video_production';
  const hasContact = !!r.contact_name && !!r.contact_email;
  return serviceOk && locationOk && onsiteOk && budgetOk && durationOk && hasContact;
});

// CP1 (0.70): At least one quote request matches core spec (NYC, on-site, ~90s, <=$8k, with contact info)
checkpoints.push({ passed: qualifying.length > 0, weight: 0.70 });

// CP2 (0.30): For at least one qualifying request, the user chose the highest available quality (4K)
const hasUltra4K = qualifying.some(r => r.quality_preference === 'ultra_hd_4k');
checkpoints.push({ passed: hasUltra4K, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const slots = JSON.parse(localStorage.getItem('consultation_slots') || '[]');
const bookings = JSON.parse(localStorage.getItem('consultation_bookings') || '[]');
let meta = null;
try {
  meta = JSON.parse(localStorage.getItem('_metadata') || 'null');
} catch (e) {
  meta = null;
}

const baselineDateStr = meta && meta.baselineDate ? meta.baselineDate : '2026-03-03';
const base = new Date(baselineDateStr + 'T00:00:00Z');
const day = base.getUTCDay(); // 0=Sun,1=Mon,...
const daysSinceMonday = (day + 6) % 7; // Monday->0, Tuesday->1, ...
const mondayThisWeek = new Date(base.getTime());
mondayThisWeek.setUTCDate(base.getUTCDate() - daysSinceMonday);
const nextMonday = new Date(mondayThisWeek.getTime());
nextMonday.setUTCDate(mondayThisWeek.getUTCDate() + 7);
const nextSunday = new Date(nextMonday.getTime());
nextSunday.setUTCDate(nextMonday.getUTCDate() + 6);

// Find candidate slots: website_redesign, online, 30 min, next calendar week, between 14:00 and 17:00, and available
const candidateSlots = slots.filter(slot => {
  if (!slot) return false;
  if (slot.topic !== 'website_redesign') return false;
  if (slot.meeting_format !== 'online') return false;
  if (slot.duration_minutes !== 30) return false;
  const start = new Date(slot.start_datetime);
  if (!(start >= nextMonday && start <= nextSunday)) return false;
  const hour = start.getUTCHours();
  if (hour < 14 || hour > 17) return false;
  if (slot.is_available === false) return false;
  return true;
});

candidateSlots.sort((a, b) => new Date(a.start_datetime) - new Date(b.start_datetime));
const earliest = candidateSlots[0] || null;

let qualifyingBooking = null;
if (earliest) {
  qualifyingBooking = bookings.find(b =>
    b &&
    b.consultation_slot_id === earliest.id &&
    b.topic === 'website_redesign' &&
    b.meeting_format === 'online' &&
    b.company_size === '11_50'
  ) || null;
}

// CP1 (1.00): A booking exists for the earliest qualifying slot with the correct topic, format, and company size
checkpoints.push({ passed: !!qualifyingBooking, weight: 1.00 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const seoPlans = JSON.parse(localStorage.getItem('seo_plans') || '[]').filter(p => p && p.status === 'active');
const socialPlans = JSON.parse(localStorage.getItem('social_media_plans') || '[]').filter(p => p && p.status === 'active');
const blogPlans = JSON.parse(localStorage.getItem('blog_content_plans') || '[]').filter(p => p && p.status === 'active');
const bundles = JSON.parse(localStorage.getItem('marketing_bundles') || '[]');
const proposals = JSON.parse(localStorage.getItem('marketing_proposal_requests') || '[]');

const tierOrder = { basic: 0, standard: 1, premium: 2, advanced: 3 };

// Determine most advanced SEO plan within $500
const seoCandidates = seoPlans.filter(p => typeof p.monthly_price === 'number' && p.monthly_price <= 500);
let bestSeo = null;
if (seoCandidates.length > 0) {
  bestSeo = seoCandidates.slice().sort((a, b) => {
    const tierDiff = (tierOrder[b.tier] || 0) - (tierOrder[a.tier] || 0);
    if (tierDiff !== 0) return tierDiff;
    return (b.monthly_price || 0) - (a.monthly_price || 0);
  })[0];
}

// Determine highest-tier social plan that keeps subtotal <= $900 with chosen SEO
let bestSocial = null;
if (bestSeo) {
  const socialCandidates = socialPlans.filter(p =>
    typeof p.monthly_price === 'number' &&
    (bestSeo.monthly_price + p.monthly_price) <= 900
  );
  if (socialCandidates.length > 0) {
    bestSocial = socialCandidates.slice().sort((a, b) => {
      const tierDiff = (tierOrder[b.tier] || 0) - (tierOrder[a.tier] || 0);
      if (tierDiff !== 0) return tierDiff;
      return (b.monthly_price || 0) - (a.monthly_price || 0);
    })[0];
  }
}

// Determine lowest-priced blog plan (>=1 post) that keeps total <= $900
let bestBlog = null;
if (bestSeo && bestSocial) {
  const blogCandidates = blogPlans.filter(p => {
    if (typeof p.posts_per_month !== 'number' || p.posts_per_month < 1) return false;
    if (typeof p.monthly_price !== 'number') return false;
    const total = bestSeo.monthly_price + bestSocial.monthly_price + p.monthly_price;
    return total <= 900;
  });
  if (blogCandidates.length > 0) {
    bestBlog = blogCandidates.slice().sort((a, b) => (a.monthly_price || 0) - (b.monthly_price || 0))[0];
  }
}

let qualifyingBundle = null;
if (bestSeo && bestSocial && bestBlog) {
  const expectedTotal = bestSeo.monthly_price + bestSocial.monthly_price + bestBlog.monthly_price;
  qualifyingBundle = bundles.find(b =>
    b &&
    b.seo_plan_id === bestSeo.id &&
    b.social_media_plan_id === bestSocial.id &&
    b.blog_content_plan_id === bestBlog.id &&
    typeof b.total_monthly_price === 'number' &&
    Math.abs(b.total_monthly_price - expectedTotal) < 0.0001 &&
    (typeof b.budget_limit !== 'number' || b.budget_limit >= expectedTotal)
  ) || null;
}

let hasProposalForBundle = false;
if (qualifyingBundle) {
  hasProposalForBundle = proposals.some(pr =>
    pr &&
    pr.marketing_bundle_id === qualifyingBundle.id &&
    !!pr.contact_name &&
    !!pr.contact_email
  );
}

// CP1 (0.60): Created a marketing bundle with the correct SEO, social, and blog plans under $900/month
checkpoints.push({ passed: !!qualifyingBundle, weight: 0.60 });

// CP2 (0.40): Submitted a proposal request for that bundle with contact information
checkpoints.push({ passed: !!qualifyingBundle && hasProposalForBundle, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const caseStudies = JSON.parse(localStorage.getItem('case_studies') || '[]');
const contactRequests = JSON.parse(localStorage.getItem('case_study_contact_requests') || '[]');

// Filter retail case studies that include BOTH it_support and video_production, then sort by most recent
const filtered = caseStudies.filter(cs => {
  if (!cs || cs.industry !== 'retail') return false;
  const services = Array.isArray(cs.services) ? cs.services : [];
  return services.includes('it_support') && services.includes('video_production');
});

filtered.sort((a, b) => {
  const da = a.published_at ? new Date(a.published_at).getTime() : 0;
  const db = b.published_at ? new Date(b.published_at).getTime() : 0;
  return db - da; // most recent first
});

const firstCaseStudy = filtered[0] || null;

let hasQualifyingContact = false;
if (firstCaseStudy) {
  hasQualifyingContact = contactRequests.some(req =>
    req &&
    req.case_study_id === firstCaseStudy.id &&
    !!req.message &&
    !!req.contact_name &&
    !!req.contact_email
  );
}

// CP1 (1.00): Submitted a sales contact request from the correct first filtered case study with a message and contact info
checkpoints.push({ passed: hasQualifyingContact, weight: 1.00 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('help_articles') || '[]');
const readingLists = JSON.parse(localStorage.getItem('reading_lists') || '[]');
const readingListItems = JSON.parse(localStorage.getItem('reading_list_items') || '[]');

// Emulate searchHelpArticles('cloud backup', 'cloud_services', 'most_recent')
const query = 'cloud backup';
const q = query.toLowerCase();

let filtered = articles.filter(a => a && a.is_published && a.topic === 'cloud_services');

filtered = filtered.filter(a => {
  const title = (a.title || '').toLowerCase();
  const content = (a.content || '').toLowerCase();
  const tags = Array.isArray(a.tags) ? a.tags.join(' ').toLowerCase() : '';
  return title.includes(q) || content.includes(q) || tags.includes(q);
});

filtered.sort((a, b) => {
  const da = a.published_at ? new Date(a.published_at).getTime() : 0;
  const db = b.published_at ? new Date(b.published_at).getTime() : 0;
  return db - da; // most recent first
});

const newest = filtered[0] || null;

let savedToReadingList = false;
if (newest) {
  const itemsForArticle = readingListItems.filter(item => item && item.help_article_id === newest.id);
  savedToReadingList = itemsForArticle.some(item =>
    !!item.reading_list_id &&
    readingLists.some(list => list && list.id === item.reading_list_id)
  );
}

// CP1 (1.00): The newest matching cloud backup article has been saved to some existing reading list
checkpoints.push({ passed: savedToReadingList, weight: 1.00 });

return checkoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const tickets = JSON.parse(localStorage.getItem('support_tickets') || '[]');

const qualifyingTicketExists = tickets.some(t => {
  if (!t) return false;
  if (t.customer_type !== 'existing_customer') return false;
  if (t.issue_category !== 'email_collaboration') return false;
  if (t.priority !== 'high') return false;
  if (!t.contact_email) return false;
  const subject = (t.subject || '').toLowerCase();
  const description = (t.description || '').toLowerCase();
  const text = subject + ' ' + description;
  const hasEmailMigration = text.includes('email migration');
  const hasStalledKeyword = text.includes('stalled') || text.includes('not completing') || text.includes('stuck');
  return hasEmailMigration && hasStalledKeyword;
});

// CP1 (1.00): A ticket exists that matches customer type, category, high priority, and stalled email migration description
checkpoints.push({ passed: qualifyingTicketExists, weight: 1.00 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const plans = JSON.parse(localStorage.getItem('rmm_plans') || '[]');
const trials = JSON.parse(localStorage.getItem('rmm_trial_signups') || '[]');

// Active, trial-eligible plans that support at least 25 devices and cost < $600
const qualifyingPlans = plans.filter(p => {
  if (!p || p.status !== 'active' || p.is_trial_available !== true) return false;
  if (typeof p.max_devices !== 'number' || p.max_devices < 25) return false;
  if (typeof p.monthly_price !== 'number' || p.monthly_price >= 600) return false;
  return true;
});

let cheapestPlan = null;
if (qualifyingPlans.length > 0) {
  cheapestPlan = qualifyingPlans.reduce((min, p) => {
    if (!min) return p;
    const mp = typeof p.monthly_price === 'number' ? p.monthly_price : Infinity;
    const mm = typeof min.monthly_price === 'number' ? min.monthly_price : Infinity;
    return mp < mm ? p : min;
  }, null);
}

// CP1 (0.50): Started a free trial for any qualifying RMM plan with business details and >=25 estimated devices
const hasTrialOnQualifyingPlan = trials.some(tr => {
  if (!tr) return false;
  const plan = qualifyingPlans.find(p => p.id === tr.rmm_plan_id);
  if (!plan) return false;
  const hasContact = !!tr.full_name && !!tr.business_email;
  const devicesOk = typeof tr.estimated_devices === 'number' && tr.estimated_devices >= 25;
  return hasContact && devicesOk;
});
checkpoints.push({ passed: hasTrialOnQualifyingPlan, weight: 0.50 });

// CP2 (0.50): There is a trial with business details and >=25 devices specifically for the lowest-priced qualifying plan
let trialOnCheapestWithDetails = false;
if (cheapestPlan) {
  trialOnCheapestWithDetails = trials.some(tr => {
    if (!tr || tr.rmm_plan_id !== cheapestPlan.id) return false;
    const hasContact = !!tr.full_name && !!tr.business_email;
    const devicesOk = typeof tr.estimated_devices === 'number' && tr.estimated_devices >= 25;
    return hasContact && devicesOk;
  });
}
checkpoints.push({ passed: trialOnCheapestWithDetails, weight: 0.50 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
